const initCompletedProjectsSlider = () => {
  const root = document.querySelector('[data-completed-projects-container]');
  if (!root) {
    return;
  }

  const container = root.querySelector('[data-completed-projects-swiper]');
  if (!container) {
    return;
  }

  const btnPrev = root.querySelector('[data-btn-prev]');
  const btnNext = root.querySelector('[data-btn-next]');

  let swiper = null;

  const shouldDestroy = () =>
    root.dataset.destroy &&
    !window.matchMedia(root.dataset.destroy).matches;

  const createSwiper = () => {
    swiper = new Swiper(container, {
      slidesPerView: 2,
      slidesPerGroup: 2,
      spaceBetween: 10,
      navigation: {
        nextEl: btnNext,
        prevEl: btnPrev,
      },
      breakpoints: {
        1200: {
          slidesPerGroup: 4,
          slidesPerView: 4,
          spaceBetween: 20,
        },
      },
    });
  };

  const update = () => {
    if (shouldDestroy()) {
      if (swiper) {
        swiper.destroy(true, true);
        swiper = null;
      }
      return;
    }

    if (!swiper) {
      createSwiper();
    }
  };

  let resizeTimeout;
  const onResize = () => {
    clearTimeout(resizeTimeout);
    resizeTimeout = setTimeout(update, 150);
  };

  update();
  window.addEventListener('resize', onResize);
};


export { initCompletedProjectsSlider };
