const initQuestionnaire = () => {
  const root = document.querySelector('[data-questionnaire]');
  if (!root) {
    return;
  }

  const body = root.querySelector('[data-questionnaire-body]');
  const list = root.querySelector('[data-questionnaire-list]');
  const items = Array.from(root.querySelectorAll('[data-step]'));
  const final = root.querySelector('[data-questionnaire-final]');
  const counters = Array.from(root.querySelectorAll('[data-counter]'));
  const transitionDuration = 300;
  const finalStep = items.length;

  if (!body || !list || !items.length || !final) {
    return;
  }

  let currentStep = items.findIndex((item) => item.classList.contains('is-active'));
  let isAnimating = false;

  if (currentStep < 0) {
    currentStep = 0;
    items[currentStep].classList.add('is-active');
  }

  const updateCounters = (index) => {
    counters.forEach((counter) => {
      counter.textContent = `${index + 1}/${items.length}`;
    });
  };

  const updateQuestionHeight = (item) => {
    list.style.height = `${item.offsetHeight}px`;
  };

  const updateBodyHeight = (element) => {
    body.style.height = `${element.offsetHeight}px`;
  };

  const showStep = (index) => {
    if (index === currentStep || index < 0 || index > finalStep || isAnimating) {
      return;
    }

    const isFinal = index === finalStep;
    const isCurrentFinal = currentStep === finalStep;
    const currentItem = isCurrentFinal ? final : items[currentStep];
    const nextItem = isFinal ? final : items[index];

    isAnimating = true;

    if (!isCurrentFinal) {
      updateQuestionHeight(currentItem);
    }

    updateBodyHeight(currentItem);

    requestAnimationFrame(() => {
      nextItem.classList.add('is-active');
      currentItem.classList.remove('is-active');
      list.classList.toggle('is-hidden', isFinal);

      if (!isFinal) {
        updateQuestionHeight(nextItem);
      }

      updateBodyHeight(nextItem);
    });

    window.setTimeout(() => {
      isAnimating = false;
    }, transitionDuration);

    if (!isFinal) {
      updateCounters(index);
    }

    currentStep = index;
  };

  const initSteps = () => {
    items.forEach((item, index) => {
      item.classList.toggle('is-active', index === currentStep);
    });
    final.classList.remove('is-active');
    list.classList.remove('is-hidden');

    updateQuestionHeight(items[currentStep]);
    updateBodyHeight(items[currentStep]);
    counters.forEach((counter) => {
      counter.textContent = `${currentStep + 1}/${items.length}`;
    });
  };

  root.querySelectorAll('[data-btn-next]').forEach((btn) => {
    btn.addEventListener('click', (e) => {
      e.preventDefault();
      showStep(currentStep + 1);
    });
  });

  root.querySelectorAll('[data-btn-prev]').forEach((btn) => {
    btn.addEventListener('click', (e) => {
      e.preventDefault();
      showStep(currentStep - 1);
    });
  });

  const ro = new ResizeObserver(() => {
    if (!isAnimating) {
      const activeItem = currentStep === finalStep ? final : items[currentStep];

      if (currentStep !== finalStep) {
        updateQuestionHeight(activeItem);
      }

      updateBodyHeight(activeItem);
    }
  });

  items.forEach((item) => ro.observe(item));
  ro.observe(final);

  initSteps();
};

export {initQuestionnaire};
